import tarfile

def search_files_in_directory(directory, extension='.txt', max_level=4, output_file='archive.tar'):
    with tarfile.open(output_file, 'w') as tar:
        for dirpath, _, filenames in os.walk(directory):
            for file in filenames:
                if file.endswith(extension):
                    file_path = os.path.join(dirpath, file)
                    tar.add(file_path, arcname=os.path.relpath(file_path, start=directory))
            if len(os.listdir(dirpath)) > max_level:
                separator = '**/' * (max_level + 1)
                tar.add(os.path.join(dirpath, os.listdir(dirpath)[0]), arcname=separator)
    tar.close()
    return output_file
